const execution = $json.execution || {};
const workflow = $json.workflow || {};
return [{
  json: {
    error_id: `err_${Date.now()}`,
    workflow_name: workflow.name || 'unknown',
    workflow_id: workflow.id || 'unknown',
    execution_id: execution.id || 'unknown',
    last_node_executed: execution.lastNodeExecuted || 'unknown',
    error_message: execution.error?.message || $json.error?.message || 'Unknown workflow error',
    input_summary: execution.mode ? `mode=${execution.mode}` : 'summary unavailable',
    captured_at: new Date().toISOString()
  }
}];

return [{
  json: {
    ...$json,
    recovery_advice: [
      'Review the failed execution in n8n execution history.',
      'Inspect the last executed node and sanitized input summary.',
      'Fix the workflow or payload, then rerun manually before reactivating automation.'
    ],
    notification_markdown: [
      '# Goal-Driven Workflow Error',
      '',
      `- Workflow: ${$json.workflow_name}`,
      `- Execution: ${$json.execution_id}`,
      `- Last node: ${$json.last_node_executed}`,
      `- Error: ${$json.error_message}`,
      '',
      '## Recommended recovery',
      ...[
        'Review the failed execution in n8n execution history.',
        'Inspect the last executed node and sanitized input summary.',
        'Fix the workflow or payload, then rerun manually before reactivating automation.'
      ].map((item) => `- ${item}`)
    ].join('\n')
  }
}];
